const unescape = (s: string) =>
    s
        .replace(/\\r\\n/g, "\n")
        .replace(/\\n/g, "\n")
        .replace(/\\r/g, "\n")
        .replace(/\\t/g, "\t");

export const formatted: Row[] = resultArray20Reps.map((r) => ({
    ...r,
    sqlQuery: unescape(r.sqlQuery),
    pipeQuery: unescape(r.pipeQuery),
}));

